sql:
SELECT COUNT(member_id) 
FROM family_members
WHERE age > 50;

SELECT relationship, COUNT(member_id) AS count
FROM family_members
GROUP BY relationship;

SELECT family_members.name, jobs.job_name
FROM family_members
JOIN jobs ON family_members.job_id = jobs.job_id;

external_knowledge:
- 'switched jobs' is synonymous with 'job changes' in this context;
- 'individuals in the family' refers to 'family members';
- The count of job changes gives an insight into the career mobility of each family member.

sql:
SELECT name, age
FROM family_members
WHERE vehicle_id IS NOT NULL;

SELECT family_members.name, family_members.address, vehicles.vehicle_name
FROM family_members
JOIN vehicles ON family_members.vehicle_id = vehicles.vehicle_id;

SELECT member_id, COUNT(*) AS relationships_count
FROM family_relationships
GROUP BY member_id;
